// src/components/StyleEditor/StyleEditor.jsx
import React, { useState, useEffect, useCallback } from 'react';
import { styleService } from '../../services/styleService';
import './StyleEditor.css';

const StyleEditor = ({ conferenceId, onSave, onClose }) => {
    const [styles, setStyles] = useState(null);
    const [loading, setLoading] = useState(false);
    const [activeTab, setActiveTab] = useState('general');
    const [saving, setSaving] = useState(false);
    
    // Оборачиваем loadStyles в useCallback, чтобы избежать лишних пересозданий
    const loadStyles = useCallback(async () => {
        setLoading(true);
        try {
            const loadedStyles = await styleService.getConferenceStyles(conferenceId);
            setStyles(loadedStyles);
        } catch (error) {
            console.error('Ошибка загрузки стилей:', error);
        } finally {
            setLoading(false);
        }
    }, [conferenceId]); // Зависимость - conferenceId
    
    useEffect(() => {
        if (conferenceId) {
            loadStyles();
        }
    }, [conferenceId, loadStyles]); // Добавляем loadStyles в зависимости
    
    const handleStyleChange = (key, value) => {
        setStyles(prev => ({
            ...prev,
            [key]: value
        }));
    };
    
    const handleSave = async () => {
        setSaving(true);
        try {
            const token = localStorage.getItem('token');
            await styleService.saveConferenceStyles(conferenceId, styles, token);
            if (onSave) onSave();
            alert('Стили успешно сохранены!');
        } catch (error) {
            console.error('Ошибка сохранения:', error);
            alert('Ошибка при сохранении стилей: ' + error.message);
        } finally {
            setSaving(false);
        }
    };
    
    if (loading) return <div className="style-editor-loading">Загрузка стилей...</div>;
    if (!styles) return null;
    
    return (
        <div className="style-editor-modal">
            <div className="style-editor-container">
                <div className="style-editor-header">
                    <h2>Настройка стилей конференции</h2>
                    <button className="close-btn" onClick={onClose}>×</button>
                </div>
                
                <div className="style-editor-tabs">
                    <button className={activeTab === 'general' ? 'active' : ''} 
                            onClick={() => setActiveTab('general')}>
                        Общие
                    </button>
                    <button className={activeTab === 'title' ? 'active' : ''} 
                            onClick={() => setActiveTab('title')}>
                        Заголовок
                    </button>
                    <button className={activeTab === 'authors' ? 'active' : ''} 
                            onClick={() => setActiveTab('authors')}>
                        Авторы
                    </button>
                    <button className={activeTab === 'abstract' ? 'active' : ''} 
                            onClick={() => setActiveTab('abstract')}>
                        Аннотация
                    </button>
                    <button className={activeTab === 'text' ? 'active' : ''} 
                            onClick={() => setActiveTab('text')}>
                        Текст
                    </button>
                    <button className={activeTab === 'tables' ? 'active' : ''} 
                            onClick={() => setActiveTab('tables')}>
                        Таблицы
                    </button>
                </div>
                
                <div className="style-editor-content">
                    {activeTab === 'general' && (
                        <div className="style-group">
                            <div className="style-field">
                                <label>Цвет фона страницы</label>
                                <input
                                    type="color"
                                    value={styles.page_background}
                                    onChange={(e) => handleStyleChange('page_background', e.target.value)}
                                />
                            </div>
                            
                            <div className="style-field">
                                <label>Отступ контейнера (px)</label>
                                <input
                                    type="number"
                                    value={styles.container_padding}
                                    onChange={(e) => handleStyleChange('container_padding', parseInt(e.target.value))}
                                    min="0"
                                    max="100"
                                />
                            </div>
                            
                            <div className="style-field">
                                <label>Основной шрифт</label>
                                <select
                                    value={styles.font_family}
                                    onChange={(e) => handleStyleChange('font_family', e.target.value)}
                                >
                                    <option value="Arial, sans-serif">Arial</option>
                                    <option value="Times New Roman, serif">Times New Roman</option>
                                    <option value="Futura PT, sans-serif">Futura PT</option>
                                    <option value="Georgia, serif">Georgia</option>
                                    <option value="Verdana, sans-serif">Verdana</option>
                                </select>
                            </div>
                        </div>
                    )}
                    
                    {activeTab === 'title' && (
                        <div className="style-group">
                            <div className="style-field">
                                <label>Размер шрифта заголовка (px)</label>
                                <input
                                    type="number"
                                    value={styles.title_font_size}
                                    onChange={(e) => handleStyleChange('title_font_size', parseInt(e.target.value))}
                                    min="12"
                                    max="72"
                                />
                            </div>
                            
                            <div className="style-field">
                                <label>Цвет заголовка</label>
                                <input
                                    type="color"
                                    value={styles.title_color}
                                    onChange={(e) => handleStyleChange('title_color', e.target.value)}
                                />
                            </div>
                            
                            <div className="style-field">
                                <label>Выравнивание</label>
                                <select
                                    value={styles.title_text_align}
                                    onChange={(e) => handleStyleChange('title_text_align', e.target.value)}
                                >
                                    <option value="left">По левому краю</option>
                                    <option value="center">По центру</option>
                                    <option value="right">По правому краю</option>
                                </select>
                            </div>
                            
                            <div className="style-field">
                                <label>Отступ снизу (px)</label>
                                <input
                                    type="number"
                                    value={styles.title_margin_bottom}
                                    onChange={(e) => handleStyleChange('title_margin_bottom', parseInt(e.target.value))}
                                    min="0"
                                    max="100"
                                />
                            </div>
                        </div>
                    )}
                    
                    {activeTab === 'authors' && (
                        <div className="style-group">
                            <div className="style-field">
                                <label>Размер шрифта авторов (px)</label>
                                <input
                                    type="number"
                                    value={styles.authors_font_size}
                                    onChange={(e) => handleStyleChange('authors_font_size', parseInt(e.target.value))}
                                    min="10"
                                    max="48"
                                />
                            </div>
                            
                            <div className="style-field">
                                <label>Цвет авторов</label>
                                <input
                                    type="color"
                                    value={styles.authors_color}
                                    onChange={(e) => handleStyleChange('authors_color', e.target.value)}
                                />
                            </div>
                            
                            <div className="style-field">
                                <label>Выравнивание</label>
                                <select
                                    value={styles.authors_text_align}
                                    onChange={(e) => handleStyleChange('authors_text_align', e.target.value)}
                                >
                                    <option value="left">По левому краю</option>
                                    <option value="center">По центру</option>
                                    <option value="right">По правому краю</option>
                                </select>
                            </div>
                        </div>
                    )}
                    
                    {activeTab === 'abstract' && (
                        <div className="style-group">
                            <div className="style-field">
                                <label>Размер шрифта аннотации (px)</label>
                                <input
                                    type="number"
                                    value={styles.abstract_font_size}
                                    onChange={(e) => handleStyleChange('abstract_font_size', parseInt(e.target.value))}
                                    min="10"
                                    max="24"
                                />
                            </div>
                            
                            <div className="style-field">
                                <label>Межстрочный интервал</label>
                                <input
                                    type="number"
                                    step="0.1"
                                    value={styles.abstract_line_height}
                                    onChange={(e) => handleStyleChange('abstract_line_height', parseFloat(e.target.value))}
                                    min="1"
                                    max="2.5"
                                />
                            </div>
                            
                            <div className="style-field">
                                <label>Цвет текста</label>
                                <input
                                    type="color"
                                    value={styles.abstract_color}
                                    onChange={(e) => handleStyleChange('abstract_color', e.target.value)}
                                />
                            </div>
                        </div>
                    )}
                    
                    {activeTab === 'text' && (
                        <div className="style-group">
                            <div className="style-field">
                                <label>Размер основного текста (px)</label>
                                <input
                                    type="number"
                                    value={styles.text_font_size}
                                    onChange={(e) => handleStyleChange('text_font_size', parseInt(e.target.value))}
                                    min="10"
                                    max="24"
                                />
                            </div>
                            
                            <div className="style-field">
                                <label>Межстрочный интервал</label>
                                <input
                                    type="number"
                                    step="0.1"
                                    value={styles.text_line_height}
                                    onChange={(e) => handleStyleChange('text_line_height', parseFloat(e.target.value))}
                                    min="1"
                                    max="2.5"
                                />
                            </div>
                            
                            <div className="style-field">
                                <label>Цвет текста</label>
                                <input
                                    type="color"
                                    value={styles.text_color}
                                    onChange={(e) => handleStyleChange('text_color', e.target.value)}
                                />
                            </div>
                        </div>
                    )}
                    
                    {activeTab === 'tables' && (
                        <div className="style-group">
                            <div className="style-field">
                                <label>Цвет границ таблицы</label>
                                <input
                                    type="color"
                                    value={styles.table_border_color}
                                    onChange={(e) => handleStyleChange('table_border_color', e.target.value)}
                                />
                            </div>
                            
                            <div className="style-field">
                                <label>Цвет фона заголовка таблицы</label>
                                <input
                                    type="color"
                                    value={styles.table_header_bg}
                                    onChange={(e) => handleStyleChange('table_header_bg', e.target.value)}
                                />
                            </div>
                            
                            <div className="style-field">
                                <label>Отступ в ячейках (px)</label>
                                <input
                                    type="number"
                                    value={styles.table_cell_padding}
                                    onChange={(e) => handleStyleChange('table_cell_padding', parseInt(e.target.value))}
                                    min="2"
                                    max="20"
                                />
                            </div>
                        </div>
                    )}
                </div>
                
                <div className="style-editor-actions">
                    <button type="button" onClick={onClose} className="btn-secondary">
                        Отмена
                    </button>
                    <button type="button" onClick={handleSave} disabled={saving} className="btn-primary">
                        {saving ? 'Сохранение...' : 'Сохранить стили'}
                    </button>
                </div>
            </div>
        </div>
    );
};

export default StyleEditor;
